import os
import subprocess
import sys

def generate_requirements_txt():
    """Generate requirements.txt with hashes for dependencies."""
    try:
        subprocess.run([sys.executable, '-m', 'pip', 'freeze', '--require-hashes'], check=True)
        with open('requirements.txt', 'w') as f:
            subprocess.run([sys.executable, '-m', 'pip', 'freeze', '--require-hashes'], stdout=f, check=True)
        print("requirements.txt generated with hashes.")
    except subprocess.CalledProcessError as e:
        print(f"Error generating requirements.txt: {e}")

def update_requirements_txt():
    """Update requirements.txt with the latest versions and hashes."""
    try:
        subprocess.run([sys.executable, '-m', 'pip', 'install', '--upgrade', '-r', 'requirements.txt'], check=True)
        generate_requirements_txt()
        print("requirements.txt updated with latest versions and hashes.")
    except subprocess.CalledProcessError as e:
        print(f"Error updating requirements.txt: {e}")

def generate_poetry_lock():
    """Generate or update poetry.lock file for dependencies."""
    try:
        subprocess.run(['poetry', 'update'], check=True)
        print("poetry.lock file generated/updated.")
    except subprocess.CalledProcessError as e:
        print(f"Error generating/updating poetry.lock: {e}")

def install_dependencies():
    """Install dependencies from requirements.txt or poetry.lock."""
    if os.path.exists('requirements.txt'):
        try:
            subprocess.run([sys.executable, '-m', 'pip', 'install', '-r', 'requirements.txt'], check=True)
            print("Dependencies installed from requirements.txt.")
        except subprocess.CalledProcessError as e:
            print(f"Error installing dependencies from requirements.txt: {e}")
    elif os.path.exists('poetry.lock'):
        try:
            subprocess.run(['poetry', 'install'], check=True)
            print("Dependencies installed from poetry.lock.")
        except subprocess.CalledProcessError as e:
            print(f"Error installing dependencies from poetry.lock: {e}")
    else:
        print("No dependency file found.")

def main():
    """Main function to manage dependencies."""
    action = input("Choose an action (generate, update, install): ").strip().lower()
    if action == 'generate':
        generate_requirements_txt()
    elif action == 'update':
        update_requirements_txt()
    elif action == 'install':
        install_dependencies()
    else:
        print("Invalid action. Please choose 'generate', 'update', or 'install'.")

if __name__ == "__main__":
    main()